import React, { useState, useEffect } from 'react';
import { getReservationsByOrganiser, getAllCancellations, updateRefundStatus } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const AdminBookingsPage = () => {
  const { user } = useAuth();
  const [reservations, setReservations] = useState([]);
  const [cancellations, setCancellations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState('bookings');
  const [search, setSearch] = useState('');

  const load = async () => {
    try {
      const [resRes, canRes] = await Promise.all([
        getReservationsByOrganiser(user.userId),
        getAllCancellations(),
      ]);
      setReservations(resRes.data.data || []);
      setCancellations(canRes.data.data || []);
    } catch { toast.error('Failed to load'); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const handleRefundStatus = async (id, status) => {
    try {
      await updateRefundStatus(id, status);
      toast.success(`Refund status updated to ${status}`);
      load();
    } catch { toast.error('Failed to update'); }
  };

  const filteredRes = reservations.filter(r =>
    !search || r.refCode?.toLowerCase().includes(search.toLowerCase()) ||
    r.user?.name?.toLowerCase().includes(search.toLowerCase()) ||
    r.slot?.event?.name?.toLowerCase().includes(search.toLowerCase())
  );

  const filteredCan = cancellations.filter(c =>
    !search || c.reservation?.refCode?.toLowerCase().includes(search.toLowerCase())
  );

  const STATUS_BADGE = { CONFIRMED:'badge-success', PENDING:'badge-warning', CANCELLED:'badge-danger' };
  const REFUND_BADGE = { PROCESSED:'badge-success', PENDING:'badge-warning', REJECTED:'badge-danger' };

  return (
    <div className="container page-content" style={{ background:'var(--bg-secondary)', minHeight:'100vh', paddingLeft:'28px', paddingRight:'28px' }}>
      <div className="page-header">
        <h1 className="page-title">BOOKINGS & CANCELLATIONS</h1>
        <p className="page-subtitle">Manage all reservations for your events</p>
      </div>

      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', flexWrap:'wrap', gap:'12px', marginBottom:'20px' }}>
        <div className="tabs" style={{ marginBottom:0, borderBottom:'none' }}>
          <button className={`tab-btn ${tab==='bookings'?'active':''}`} onClick={() => setTab('bookings')}>
            Bookings <span style={{ marginLeft:'4px', padding:'1px 7px', borderRadius:'99px', fontSize:'11px', background:'var(--bg-secondary)', color:'var(--text-muted)' }}>{reservations.length}</span>
          </button>
          <button className={`tab-btn ${tab==='cancellations'?'active':''}`} onClick={() => setTab('cancellations')}>
            Cancellations <span style={{ marginLeft:'4px', padding:'1px 7px', borderRadius:'99px', fontSize:'11px', background:'var(--bg-secondary)', color:'var(--text-muted)' }}>{cancellations.length}</span>
          </button>
        </div>
        <input className="form-input" placeholder="Search by ref, user, event..." value={search} onChange={e => setSearch(e.target.value)}
          style={{ width:'280px' }} />
      </div>

      {loading ? (
        <div className="loading-center"><div className="spinner" /></div>
      ) : tab === 'bookings' ? (
        filteredRes.length === 0 ? (
          <div className="empty-state"><div className="empty-state-icon">🎟</div><h3>No Bookings Found</h3></div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead>
                <tr><th>Ref Code</th><th>User</th><th>Event</th><th>Date</th><th>Venue</th><th>Amount</th><th>Status</th><th>Booked On</th></tr>
              </thead>
              <tbody>
                {filteredRes.map(r => (
                  <tr key={r.reservationId}>
                    <td><span style={{ fontFamily:'var(--font-mono)', fontSize:'12px', color:'var(--accent)' }}>{r.refCode}</span></td>
                    <td>
                      <div style={{ fontWeight:600, fontSize:'13px' }}>{r.user?.name}</div>
                      <div style={{ fontSize:'11px', color:'var(--text-muted)' }}>{r.user?.mail}</div>
                    </td>
                    <td style={{ fontWeight:600 }}>{r.slot?.event?.name}</td>
                    <td>{r.slot?.showDate}</td>
                    <td style={{ color:'var(--text-secondary)' }}>{r.slot?.location?.locName}</td>
                    <td style={{ fontWeight:700, color:'var(--accent)' }}>₹{parseFloat(r.amount||0).toFixed(2)}</td>
                    <td><span className={`badge ${STATUS_BADGE[r.status]||'badge-muted'}`}>{r.status}</span></td>
                    <td style={{ color:'var(--text-muted)', fontSize:'12px' }}>{r.reservedDate ? new Date(r.reservedDate).toLocaleDateString('en-IN') : '-'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )
      ) : (
        filteredCan.length === 0 ? (
          <div className="empty-state"><div className="empty-state-icon">❌</div><h3>No Cancellations</h3></div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead>
                <tr><th>Ref Code</th><th>User</th><th>Event</th><th>Reason</th><th>Refund Amt</th><th>Refund Status</th><th>Date</th><th>Actions</th></tr>
              </thead>
              <tbody>
                {filteredCan.map(c => (
                  <tr key={c.cancellationId}>
                    <td><span style={{ fontFamily:'var(--font-mono)', fontSize:'12px', color:'var(--accent)' }}>{c.reservation?.refCode}</span></td>
                    <td>
                      <div style={{ fontWeight:600, fontSize:'13px' }}>{c.user?.name}</div>
                      <div style={{ fontSize:'11px', color:'var(--text-muted)' }}>{c.user?.mail}</div>
                    </td>
                    <td style={{ fontWeight:600 }}>{c.reservation?.slot?.event?.name || '—'}</td>
                    <td style={{ color:'var(--text-secondary)', maxWidth:'200px' }}>
                      <span style={{ display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical', overflow:'hidden', fontSize:'12px' }}>{c.reason || '—'}</span>
                    </td>
                    <td style={{ fontWeight:700, color:'var(--green)' }}>₹{parseFloat(c.refundAmount||0).toFixed(2)}</td>
                    <td><span className={`badge ${REFUND_BADGE[c.refundStatus]||'badge-muted'}`}>{c.refundStatus}</span></td>
                    <td style={{ color:'var(--text-muted)', fontSize:'12px' }}>{c.date ? new Date(c.date).toLocaleDateString('en-IN') : '-'}</td>
                    <td>
                      {c.refundStatus === 'PENDING' && (
                        <div style={{ display:'flex', gap:'4px' }}>
                          <button onClick={() => handleRefundStatus(c.cancellationId,'PROCESSED')} className="btn btn-success btn-sm" style={{ fontSize:'11px', padding:'4px 8px' }}>Approve</button>
                          <button onClick={() => handleRefundStatus(c.cancellationId,'REJECTED')} className="btn btn-danger btn-sm" style={{ fontSize:'11px', padding:'4px 8px' }}>Reject</button>
                        </div>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )
      )}
    </div>
  );
};

export default AdminBookingsPage;
